head.b:skin:
*{margin:0;padding:0;box-sizing:border-box}
:root{--gold:#d4af37;--gold-light:#f0d060;--gold-dark:#b8960f;--dark:#0a0e17;--dark-2:#111827;--dark-3:#1a2332;--dark-card:#0f1724;--text:#e2e8f0;--text-muted:#8899aa;--green:#00c853;--red:#ff1744;--blue:#2196f3;--purple:#7c3aed;--orange:#ff9800;--teal:#00bcd4;--pink:#e91e63;--colombia-blue:#003893}
html{scroll-behavior:smooth}
body{font-family:Segoe UI,system-ui,-apple-system,sans-serif;background:var(--dark);color:var(--text);line-height:1.6;overflow-x:hidden}
a{color:var(--gold);text-decoration:none;transition:color .3s}a:hover{color:var(--gold-light)}
img{max-width:100%;height:auto;display:block}
.container{max-width:1200px;margin:0 auto;padding:0 1.5rem}
/* NAVBAR */
.navbar{position:fixed;top:0;width:100%;z-index:1000;background:rgba(10,14,23,.97);backdrop-filter:blur(12px);border-bottom:1px solid rgba(212,175,55,.1)}
.navbar .container{display:flex;justify-content:space-between;align-items:center;padding:.65rem 1.5rem;max-width:1200px;margin:0 auto}
.logo{display:flex;align-items:center;gap:.4rem;font-size:1.4rem;font-weight:800;color:var(--gold);text-decoration:none;white-space:nowrap}
.nav-links{display:flex;gap:1.2rem;list-style:none;align-items:center;flex-wrap:wrap}
.nav-links a{font-size:.85rem;color:var(--text-muted);text-decoration:none;position:relative}
.nav-links a:hover{color:var(--gold)}
.nav-cta{background:linear-gradient(135deg,var(--gold),var(--gold-light));color:var(--dark)!important;padding:.45rem 1.2rem;border-radius:50px;font-weight:700!important;font-size:.8rem!important;white-space:nowrap}
.hamburger{display:none;flex-direction:column;cursor:pointer;gap:5px;padding:4px;z-index:1001;background:none;border:none}
.hamburger span{display:block;width:26px;height:2px;background:var(--gold);border-radius:2px;transition:all .3s}
.hamburger.active span:nth-child(1){transform:rotate(45deg) translate(5px,5px)}
.hamburger.active span:nth-child(2){opacity:0}
.hamburger.active span:nth-child(3){transform:rotate(-45deg) translate(5px,-5px)}
@media(max-width:820px){
.nav-links{position:fixed;top:0;right:-100%;width:280px;height:100vh;background:var(--dark-3);flex-direction:column;padding:5rem 2rem;gap:.8rem;border-left:1px solid rgba(212,175,55,.12);transition:right .35s;z-index:999;align-items:flex-start}
.nav-links.open{right:0}
.nav-links a{font-size:1rem;padding:.4rem 0}
.hamburger{display:flex}
}
/* HERO */
.hero{min-height:92vh;display:flex;align-items:center;position:relative;overflow:hidden;padding:110px 0 70px}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 50%,rgba(212,175,55,.08),transparent 50%),radial-gradient(circle at 80% 20%,rgba(124,58,237,.05),transparent 50%)}
.hero-grid{display:grid;grid-template-columns:1fr 1fr;gap:3rem;align-items:center;position:relative;z-index:1}
.hero-content h1{font-size:3.3rem;font-weight:900;line-height:1.1;margin-bottom:1rem;background:linear-gradient(135deg,var(--gold),var(--gold-light),#fff);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.hero-content .subtitle{font-size:1.05rem;color:var(--text-muted);margin-bottom:1.8rem;max-width:520px;line-height:1.7}
.hero-buttons{display:flex;gap:.8rem;flex-wrap:wrap}
.btn{display:inline-flex;align-items:center;gap:.5rem;padding:.8rem 1.8rem;border-radius:50px;font-weight:600;font-size:.92rem;cursor:pointer;border:none;text-decoration:none;line-height:1;transition:all .3s}
.btn-primary{background:linear-gradient(135deg,var(--gold),var(--gold-light));color:var(--dark);box-shadow:0 4px 20px rgba(212,175,55,.25)}
.btn-primary:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(212,175,55,.35);color:var(--dark)}
.btn-outline{background:transparent;color:var(--gold);border:2px solid var(--gold)}
.btn-outline:hover{background:rgba(212,175,55,.1);transform:translateY(-2px)}
.hero-stats{display:flex;gap:2rem;margin-top:2rem;padding-top:1.5rem;border-top:1px solid rgba(212,175,55,.1)}
.hero-stat h3{font-size:1.6rem;color:var(--gold)}.hero-stat p{font-size:.78rem;color:var(--text-muted)}
.region-badge{display:inline-flex;align-items:center;gap:.35rem;background:rgba(212,175,55,.1);color:var(--gold);border:1px solid rgba(212,175,55,.2);padding:.2rem .8rem;border-radius:50px;font-size:.72rem;font-weight:600;margin-bottom:.8rem}
/* SECTIONS */
.section{padding:80px 0}
.section-header{text-align:center;margin-bottom:3rem}
.section-tag{display:inline-block;background:rgba(212,175,55,.1);color:var(--gold);padding:.25rem .9rem;border-radius:50px;font-size:.75rem;font-weight:600;text-transform:uppercase;letter-spacing:1px;margin-bottom:.6rem}
.section-header h2{font-size:2.3rem;font-weight:800;margin-bottom:.7rem}
.section-header p{color:var(--text-muted);font-size:1rem;max-width:560px;margin:0 auto}
/* ABOUT */
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:3.5rem;align-items:center}
.about-text h2{font-size:2.1rem;font-weight:800;margin-bottom:1rem}
.about-text p{color:var(--text-muted);margin-bottom:.8rem;font-size:.95rem}
.about-features{display:grid;grid-template-columns:1fr 1fr;gap:.6rem;margin-top:1.2rem}
.about-feature{display:flex;align-items:center;gap:.5rem;font-size:.85rem;color:var(--text-muted)}
.about-feature .check{color:var(--green);font-weight:700}
.about-visual{display:grid;grid-template-columns:1fr 1fr;gap:.8rem}
.stat-box{background:var(--dark-card);border:1px solid rgba(212,175,55,.08);border-radius:14px;padding:1.3rem;text-align:center}
.stat-box h3{font-size:1.8rem;color:var(--gold)}.stat-box p{color:var(--text-muted);font-size:.78rem}
/* CATEGORIES */
.categories-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:1rem}
.category-card{background:var(--dark-card);border:1px solid rgba(212,175,55,.06);border-radius:18px;padding:1.6rem;transition:all .4s;position:relative;overflow:hidden}
.category-card:hover{border-color:rgba(212,175,55,.25);transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,.3)}
.category-icon{width:46px;height:46px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.3rem;margin-bottom:.8rem}
.category-card h3{font-size:1.1rem;margin-bottom:.4rem}
.category-card p{color:var(--text-muted);font-size:.85rem;line-height:1.5}
.icon-inversiones{background:rgba(212,175,55,.15)}.icon-etf{background:rgba(124,58,237,.15)}.icon-acciones{background:rgba(0,200,83,.15)}.icon-forex{background:rgba(33,150,243,.15)}.icon-binarias{background:rgba(255,23,68,.15)}.icon-indices{background:rgba(255,152,0,.15)}.icon-materias{background:rgba(139,195,74,.15)}.icon-cripto{background:rgba(255,193,7,.15)}.icon-ahorro{background:rgba(0,188,212,.15)}.icon-ingresos{background:rgba(233,30,99,.15)}
/* PLATFORMS */
.platforms-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:.8rem}
.platform-card{background:var(--dark-card);border:1px solid rgba(212,175,55,.06);border-radius:14px;padding:1.3rem;text-align:center;transition:all .3s}
.platform-card:hover{border-color:rgba(212,175,55,.2);transform:translateY(-3px)}
.platform-card .emoji{font-size:2rem;margin-bottom:.5rem;display:block}
.platform-card h3{font-size:.9rem;margin-bottom:.2rem}
.platform-card p{color:var(--text-muted);font-size:.75rem;margin-bottom:.6rem}
.platform-tag{display:inline-block;padding:.12rem .55rem;border-radius:50px;font-size:.62rem;font-weight:700;background:rgba(0,200,83,.15);color:var(--green)}
/* COLOMBIA */
.colombia-section{background:linear-gradient(135deg,rgba(0,56,147,.04),rgba(206,17,38,.02));border-top:1px solid rgba(212,175,55,.06);border-bottom:1px solid rgba(212,175,55,.06)}
.colombia-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1.2rem}
.co-card{background:var(--dark-card);border:1px solid rgba(212,175,55,.06);border-radius:16px;padding:1.5rem;transition:all .3s}
.co-card:hover{border-color:rgba(0,56,147,.25);transform:translateY(-3px)}
.co-card h3{font-size:1.05rem;margin-bottom:.4rem}
.co-card p{color:var(--text-muted);font-size:.85rem;line-height:1.6;margin-bottom:.6rem}
.co-card .tag{display:inline-block;padding:.12rem .55rem;background:rgba(0,56,147,.1);color:var(--colombia-blue);border-radius:50px;font-size:.67rem;font-weight:600}
/* SOCIAL */
.social-section{text-align:center;background:var(--dark-2)}
.social-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:.8rem;max-width:650px;margin:0 auto}
.social-card{display:flex;flex-direction:column;align-items:center;gap:.4rem;padding:1.3rem .8rem;border-radius:14px;border:1px solid rgba(255,255,255,.05);transition:all .3s;text-decoration:none;background:var(--dark-card)}
.social-card:hover{transform:translateY(-3px)}
.social-card .icon{font-size:1.8rem}.social-card h4{font-size:.85rem;color:var(--text)}.social-card p{font-size:.72rem;color:var(--text-muted)}
/* FAQ */
.faq-grid{max-width:700px;margin:0 auto}
.faq-item{background:var(--dark-card);border:1px solid rgba(212,175,55,.06);border-radius:14px;margin-bottom:.6rem;overflow:hidden}
.faq-question{width:100%;background:none;border:none;color:var(--text);font-size:.95rem;font-weight:600;padding:1.1rem 1.3rem;text-align:left;cursor:pointer;display:flex;justify-content:space-between;align-items:center}
.faq-question .arrow{color:var(--gold);transition:transform .3s}
.faq-item.open .faq-question .arrow{transform:rotate(180deg)}
.faq-answer{max-height:0;overflow:hidden;transition:max-height .3s;padding:0 1.3rem;color:var(--text-muted);font-size:.85rem}
.faq-item.open .faq-answer{max-height:400px;padding:0 1.3rem 1rem}
/* NEWSLETTER */
.newsletter{text-align:center;padding:70px 0;background:var(--dark-2)}
.newsletter-content{max-width:500px;margin:0 auto}
.newsletter-content h2{font-size:1.8rem;margin-bottom:.6rem}
.newsletter-content p{color:var(--text-muted);margin-bottom:1.5rem;font-size:.9rem}
.newsletter-form{display:flex;gap:.5rem;max-width:420px;margin:0 auto;flex-wrap:wrap;justify-content:center}
.newsletter-form input{flex:1;min-width:180px;padding:.8rem 1.1rem;border-radius:50px;border:1px solid rgba(212,175,55,.18);background:var(--dark-card);color:var(--text);font-size:.85rem;outline:none}
.newsletter-form input:focus{border-color:var(--gold)}
.newsletter-form button{padding:.8rem 1.6rem;border-radius:50px;border:none;background:linear-gradient(135deg,var(--gold),var(--gold-light));color:var(--dark);font-weight:700;cursor:pointer;white-space:nowrap}
.newsletter-form button:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(212,175,55,.3)}
/* DISCLAIMER */
.disclaimer-bar{background:rgba(255,23,68,.03);border-top:1px solid rgba(255,23,68,.06);padding:.5rem 0;text-align:center}
.disclaimer-bar p{font-size:.68rem;color:var(--text-muted);max-width:850px;margin:0 auto;line-height:1.4}
/* FOOTER */
.footer{background:var(--dark-3);padding:45px 0 20px;border-top:1px solid rgba(212,175,55,.06)}
.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:2rem}
.footer-brand p{color:var(--text-muted);font-size:.82rem;max-width:260px;line-height:1.6;margin-top:.6rem}
.footer h4{color:var(--text);margin-bottom:.8rem;font-size:.9rem}
.footer ul{list-style:none}.footer ul li{margin-bottom:.4rem}
.footer ul li a{color:var(--text-muted);font-size:.82rem;text-decoration:none}.footer ul li a:hover{color:var(--gold)}
.footer-bottom{margin-top:1.5rem;padding-top:1rem;border-top:1px solid rgba(255,255,255,.04);display:flex;justify-content:space-between;font-size:.78rem;color:var(--text-muted);flex-wrap:wrap;gap:.6rem}
.footer-legal-links{display:flex;gap:1rem}.footer-legal-links a{color:var(--text-muted);font-size:.78rem}
/* COOKIES */
.cookies-banner{position:fixed;bottom:0;left:0;right:0;background:var(--dark-3);border-top:1px solid rgba(212,175,55,.12);padding:.8rem 1.5rem;z-index:9999;display:none}
.cookies-banner.show{display:block}
.cookies-content{max-width:1200px;margin:0 auto;display:flex;align-items:center;justify-content:space-between;gap:1rem;flex-wrap:wrap}
.cookies-text{color:var(--text-muted);font-size:.8rem;flex:1;min-width:250px}
.cookies-buttons{display:flex;gap:.5rem;flex-shrink:0}
.btn-cookies{padding:.4rem 1.1rem;border-radius:50px;border:none;font-weight:600;cursor:pointer;font-size:.78rem}
.btn-cookies.accept{background:linear-gradient(135deg,var(--gold),var(--gold-light));color:var(--dark)}
.btn-cookies.decline{background:transparent;color:var(--text-muted);border:1px solid rgba(255,255,255,.08)}
/* BACK TO TOP */
.back-to-top{position:fixed;bottom:1.5rem;right:1.5rem;width:40px;height:40px;border-radius:50%;background:linear-gradient(135deg,var(--gold),var(--gold-dark));color:var(--dark);border:none;cursor:pointer;font-size:1.1rem;display:flex;align-items:center;justify-content:center;opacity:0;visibility:hidden;transition:all .3s;z-index:999}
.back-to-top.visible{opacity:1;visibility:visible}
/* BLOG (post list) */
.blog-main{padding-top:100px;min-height:60vh}
.posts-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:1.2rem;margin-bottom:2rem}
.post-card{background:var(--dark-card);border:1px solid rgba(212,175,55,.06);border-radius:18px;overflow:hidden;transition:all .4s}
.post-card:hover{border-color:rgba(212,175,55,.2);transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,.3)}
.post-card-body{padding:1.3rem 1.5rem 1.5rem}
.post-card-body h3{font-size:1.15rem;margin-bottom:.4rem}
.post-card-body h3 a{color:var(--text)}.post-card-body h3 a:hover{color:var(--gold)}
.post-card-body p{color:var(--text-muted);font-size:.85rem;margin-bottom:.8rem;line-height:1.5}
.post-meta{display:flex;justify-content:space-between;align-items:center;font-size:.75rem;color:var(--text-muted);padding-top:.7rem;border-top:1px solid rgba(255,255,255,.04)}
.blog-pager{display:flex;justify-content:space-between;margin-top:2rem;gap:1rem;flex-wrap:wrap}
/* SINGLE POST / PAGE */
.post-body{padding:120px 0 60px}.post-body .container{max-width:800px}
.post-body h1{font-size:2.2rem;font-weight:800;line-height:1.2;margin-bottom:.6rem}
.post-body .post-date{font-size:.82rem;color:var(--text-muted);margin-bottom:.5rem}
.post-body .post-labels{margin-bottom:1rem}
.post-body .post-labels a{display:inline-block;padding:.15rem .6rem;background:rgba(212,175,55,.1);color:var(--gold);border-radius:50px;font-size:.7rem;font-weight:600;margin-right:.3rem;text-decoration:none}
.post-body .post-content{line-height:1.8}
.post-body .post-content h2{font-size:1.5rem;font-weight:700;margin:2rem 0 .8rem;color:var(--gold)}
.post-body .post-content h3{font-size:1.2rem;font-weight:600;margin:1.5rem 0 .6rem}
.post-body .post-content p{color:var(--text-muted);font-size:.95rem;margin-bottom:.8rem}
.post-body .post-content ul{list-style:none;padding:0;margin:.8rem 0}
.post-body .post-content ul li{padding:.3rem 0;color:var(--text-muted);display:flex;align-items:center;gap:.5rem;font-size:.92rem}
.post-body .post-content ul li::before{content:'\25B8';color:var(--gold);font-weight:700}
.post-body .post-content blockquote{border-left:3px solid var(--gold);padding:.8rem 1.2rem;margin:1.2rem 0;background:rgba(212,175,55,.04);border-radius:0 12px 12px 0}
.post-body .post-nav{display:flex;justify-content:space-between;margin-top:3rem;padding-top:1.5rem;border-top:1px solid rgba(255,255,255,.04)}
.post-body .post-nav a{font-size:.85rem;color:var(--text-muted)}.post-body .post-nav a:hover{color:var(--gold)}
/* 404 */
.page-404{min-height:70vh;display:flex;align-items:center;justify-content:center;text-align:center;padding-top:100px}
.page-404 h1{font-size:5rem;color:var(--gold)}.page-404 p{color:var(--text-muted);margin:1rem 0 2rem}
/* MODAL */
.modal-overlay.open{display:flex!important}
/* FADE IN */
.fade-in{opacity:0;transform:translateY(22px);transition:all .6s ease}.fade-in.visible{opacity:1;transform:translateY(0)}
/* RESPONSIVE */
@media(max-width:1024px){
.hero-grid{grid-template-columns:1fr;text-align:center}
.hero-content h1{font-size:2.5rem}.hero-buttons,.hero-stats{justify-content:center}
.about-grid{grid-template-columns:1fr;text-align:center}
.about-visual{max-width:380px;margin:0 auto}.footer-grid{grid-template-columns:1fr 1fr}
}
@media(max-width:768px){
.hero-content h1{font-size:1.9rem}.section-header h2{font-size:1.7rem}
.hero-stats{flex-direction:column;gap:1rem}.floating-card{display:none}
.footer-grid{grid-template-columns:1fr}.footer-bottom{flex-direction:column;text-align:center}
}
@media(max-width:480px){
.hero{padding:95px 0 50px;min-height:auto}.hero-content h1{font-size:1.6rem}
.posts-grid{grid-template-columns:1fr}
}

body.script:
(function(){var n=document.getElementById('navbar');n&&window.addEventListener('scroll',function(){n.classList.toggle('scrolled',window.pageYOffset>50)})
var h=document.getElementById('hamburger'),l=document.getElementById('navLinks');h&&l&&(h.addEventListener('click',function(){l.classList.toggle('open'),h.classList.toggle('active')}),document.querySelectorAll('.nav-links a').forEach(function(a){a.addEventListener('click',function(){l.classList.remove('open'),h.classList.remove('active')})}))
var fo=new IntersectionObserver(function(e){e.forEach(function(e){e.isIntersecting&&e.target.classList.add('visible')})},{threshold:.1});document.querySelectorAll('.fade-in').forEach(function(e){fo.observe(e)})
document.querySelectorAll('.faq-question').forEach(function(b){b.addEventListener('click',function(){var i=this.parentElement,o=i.classList.contains('open');document.querySelectorAll('.faq-item.open').forEach(function(e){e.classList.remove('open')});o||i.classList.add('open')})})
document.getElementById('newsletterForm')&&document.getElementById('newsletterForm').addEventListener('submit',function(e){e.preventDefault();var m=document.getElementById('thankyouModal');m&&(m.classList.add('open'),document.body.style.overflow='hidden')})
window.closeModal||(window.closeModal=function(){var m=document.getElementById('thankyouModal');m&&(m.classList.remove('open'),document.body.style.overflow='')})
function sc(n,v,d){document.cookie=n+'='+encodeURIComponent(v)+'; expires='+new Date(Date.now()+d*864e5).toUTCString()+'; path=/'}
var b=document.getElementById('cookiesBanner');document.cookie.match(/cookies_consent/)||setTimeout(function(){b&&b.classList.add('show')},600)
window.acceptCookies=function(){sc('cookies_consent','accepted',365);b&&b.classList.remove('show')}
window.declineCookies=function(){sc('cookies_consent','declined',30);b&&b.classList.remove('show')}
var t=document.getElementById('backToTop');t&&(window.addEventListener('scroll',function(){t.classList.toggle('visible',window.pageYOffset>400)}),t.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'})}))
})();
